切法 目的 A 股参考段 滚动窗口 IC 时序稳定性 滚动 24 个月 Mean IC（亦可用 12/36；窗口须事先约定） 牛/熊/震荡 市场状态依赖 2014–15 牛、2018 熊、2019–21 结构 制度切换 政策冲击 2016 熔断、2019 注册制、2021 量化监管 样本外 OOS 最终检验 最后 20% 时间 hold-out <pre><code>import pandas as pd

def subsample_ic(ic_series: pd.Series, periods: dict) -&gt; pd.DataFrame:
    """
    ic_series: index=trade_date, values=daily IC
    periods: {"2015_bull": ("2014-10-01", "2015-06-30"), ...}
    """
    rows = []
    for name, (start, end) in periods.items():
        sub = ic_series.loc[start:end]
        rows.append({
            "period": name,
            "mean_ic": sub.mean(),
            "icir": sub.mean() / sub.std() if sub.std() &gt; 0 else float("nan"),
            "n_days": len(sub),
        })
    return pd.DataFrame(rows)

def ic_by_year(ic: pd.Series) -&gt; pd.DataFrame:
    return ic.groupby(ic.index.year).agg(["mean", "std", "count"])
